@page "/"
@using SkiaSharp
@using SkiaSharp.Views.Blazor

<SKCanvasView OnPaintSurface="OnPaintSurface" style="width:800px;height:600px;" />

@code {
    private void OnPaintSurface(SKPaintSurfaceEventArgs args)
    {
        var canvas = args.Surface.Canvas;
        canvas.Clear(SKColors.White);
        using var paint = new SKPaint { Color = SKColors.Black, IsAntialias = true, Style = SKPaintStyle.Fill };
        using var font = new SKFont { Size = 24 };
        var coord = new SKPoint(args.Info.Width / 2, (args.Info.Height + font.Size) / 2);
        canvas.DrawText("SkiaSharp", coord, font, paint);
        Console.WriteLine($"SUCCESS: rendered {args.Info.Width}x{args.Info.Height}");
    }
}
